  assert_eq!(multi(b), Ok((&b"efgh"[..], res2)));
  assert_eq!(
    multi(c),
    Err(Err::Error(error_position!(c, ErrorKind::Tag)))
  );
  assert_eq!(multi(d), Err(Err::Incomplete(Needed::new(2))));
}

fn multi(i: &[u8]) -> IResult<&[u8], Vec<&[u8]>> {
    many1(tag("abcd")).parse(i)
